CREATE EXTENSION IF NOT EXISTS pgcrypto; CREATE EXTENSION IF NOT EXISTS pg_trgm;
CREATE TABLE accounts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),name varchar(160) NOT NULL,industry varchar(120),owner_id uuid NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE contacts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),account_id uuid NOT NULL REFERENCES accounts(id) ON DELETE CASCADE,first_name varchar(80) NOT NULL,last_name varchar(80) NOT NULL,email varchar(254) NOT NULL CHECK(email ~* '^[^@[:space:]]+@[^@[:space:]]+\.[^@[:space:]]+$'),phone varchar(30),title varchar(120),tags text[] NOT NULL DEFAULT '{}',owner_id uuid NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(account_id,email));